<template>
<section>
    <loader :is-visible="isLoading"></loader>    
    
    <tg-list :IsShowAction="false" ModuleName="RateSchedule" SubModuleCode="RateSchedule1" :LegendArray="[]" :RenderRowActionMethod="renderActions" 
    v-on:ActionButtonClick="actionButtonClick" :widgets="[]" IdentityColumn="RATE_SCHEDULE_ID" :listType="['List']" :ListData="RateScheduleData" 
    :HeaderData="Headers" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" IsSearchFieldsOnTop="false" 
    :ListDataCallBackFunction="FetchData" :showCheckBox="false"  :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')"
    :HeaderText="$t('RateScheduleHistory')" :isShowHeaderText="true" v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod" 
    v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata" :routeInfo="$router">
  
        <template v-slot:slotdata="{ data }">
            <template v-if="data.column.COLUMN_NAME == 'START_DATE'">
                <span>
                    {{ $options.filters.formatDate(data.row.START_DATE) }}
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'END_DATE'">
                <span>
                    {{ $options.filters.formatDate(data.row.END_DATE) }}
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'CREATED_AT'">
                <span>
                    {{ $options.filters.formatDateTime(data.row.CREATED_AT) }}
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'MODIFIED_AT'">
                <span>
                    {{ $options.filters.formatDateTime(data.row.MODIFIED_AT) }}
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'STATUS_ID'">
                <span v-if="data.row.STATUS_ID==1001" class="px-2 text-center bg-success text-white d-block">{{ $t('Active') }}</span>
                <span v-else class="px-2 text-center bg-danger text-white d-block">{{ $t('InActive') }}</span>
            </template>          
        </template>
    </tg-list>
</section>
</template>

<script>
import Schema from "./HistorySchema.js";
import DataService from "../../services/DataService.js";
import { locateBillingService } from "../../services/locateBillingService";

export default {
    components: {},
    data() {
        return {
            isLoading: false,
            Headers: [{
                    "COLUMN_NAME": "CLIENT_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Client',
                    "DISPLAY_ORDER": 1,
                    // settings: {
                    //     isInSlot: false
                    // }
                },
                {
                    "COLUMN_NAME": "WORK_CODE",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Work Code',
                    "DISPLAY_ORDER": 2,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "UTILITY_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Utility Name',
                    "DISPLAY_ORDER": 3,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "STATE_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'State',
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: false
                    }
                },
                {
                    "COLUMN_NAME": "BILLING_CODE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Customer Work Code',
                    "DISPLAY_ORDER": 5,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "AMOUNT",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Rate',
                    "DISPLAY_ORDER": 6,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "STATUS_ID",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Status',
                    "DISPLAY_ORDER": 7,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "START_DATE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Start Date',
                    "DISPLAY_ORDER": 8,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "END_DATE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'End Date',
                    "DISPLAY_ORDER": 9,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "MODIFIED_BY",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Modified By',
                    "DISPLAY_ORDER": 10,
                    // settings: {
                    //     isInSlot: true
                    // }
                },
                {
                    "COLUMN_NAME": "MODIFIED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Modified Date',
                    "DISPLAY_ORDER": 11,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "COMMENT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'COMMENT',
                    "DISPLAY_ORDER": 12,
                    // settings: {
                    //     isInSlot: true
                    // }
                }
            ],
            SortBy: '',
            SortExp: '',
            PageSize: 10,
            PageNumber: 1,
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            noRecords: false,
            searchCondition: '',
            RateScheduleData: [],
            listheaderbuttons: Schema.buttons,
            listActions: Schema.listActions,
            leftSearchFields: Schema.leftsearchSchema,
            CompanyId: null,
            UserId: null,
            searchBy: '',
            search: '',
            isShowAddRate: false,
            isBulkUpdateRate: false,
            isCopyRate: false,
            EditData: [],
            ClientId:'',
            clientList:[],
        }
    },
    created: async function () {
        var vm = this;
        vm.CompanyId = this.GetUserInfo.CompanyId;
        vm.UserId = this.GetUserInfo.ID;
        Schema.bindleftCommonSearchdropdown(this,'WORKCODE');       
        await vm.fetchclientlist();
        await vm.FetchData();      
        
    },
    methods: {
        fetchclientlist: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            try {
                const response = await locateBillingService.getClientList(url);
                vm.clientList = response.data.items || [];              
                vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = vm.clientList;
            } catch (error) {
                vm.clientList = [];
                vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = [];
                console.error('Error fetching client list:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                // case "Edit":
                //     this.EditAddRate(item.RATE_SCHEDULE_ID);
                //     break;
            }
        },
        leftCommonSearch: function (value) {
            debugger;
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                 this.searchCondition = value.searchCondition;
                // if (value.searchConditionJson != '') {
                // //     const fvalue = value.searchConditionJson.split('=')[1];
                // //     this.fav = fvalue;
                // // } else {
                //     this.searchCondition = value.searchCondition;
                // }
            } else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "BacktoList":
                    this.BacktoList();
                    break;
            }
        },
        BacktoList() {
            debugger;
            var vm = this;
            this.$router.push({
                path: '/RateSchedule/Index'
            });
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Edit':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        FetchData: async function () {
            debugger
            var vm = this;
            var params = '';
            vm.isLoading = true;
            var params = `pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&clientId=${vm.ClientId}&Search=${vm.searchCondition}`            
            await DataService.ListHistoryRateSchedules(params).then((response) => {
                debugger;
                if (response.data.result.length > 0) {
                    vm.isLoading = false;
                    vm.RateScheduleData = JSON.parse(response.data.result);
                    vm.TotalRecords = vm.RateScheduleData[0].TOTAL_RECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;
                } else {
                    vm.RateScheduleData = [];
                    vm.noRecords = true;
                    vm.TotalRecords = 0
                    vm.isLoading = false;
                }
            })
        },

    }
}
</script>
